import{_ as a,o as s,c as n,a4 as t}from"./chunks/framework.Cqne-ChA.js";const m=JSON.parse('{"title":"Setting up your terminal","description":"","frontmatter":{},"headers":[],"relativePath":"Guides/TerminalOnZOS.md","filePath":"Guides/TerminalOnZOS.md","lastUpdated":1680232084000}'),i={name:"Guides/TerminalOnZOS.md"};function r(o,e,l,p,c,d){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="setting-up-your-terminal" tabindex="-1">Setting up your terminal <a class="header-anchor" href="#setting-up-your-terminal" aria-label="Permalink to &quot;Setting up your terminal&quot;">​</a></h1><p>If you need to display characters that are not defined in the lower 7 bits of the general ASCII encoding, you might have problems if you choose the wrong terminal character encoding. Character encodings are a complex issue, so I will restrict this to the basics of ISO8859-1 and UTF-8 encodings and setting up your terminal emulator correctly.</p><p>I noticed when I tried to issue:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>man --locale=fr vim</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>the output did not look right. After much experimentation, I discovered it was because my terminal was set up to display UTF-8 characters, but in this case, my French man pages needed my terminal to be set up to display ISO8859-1 characters!</p><p>The solution was to change my settings for my terminal to be ISO8859-1. How you do this will vary by terminal emulator. In my case, I use <code>iTerm2</code> on a Mac, and I did:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Right-click terminal</span></span>
<span class="line"><span>Choose Edit Session</span></span>
<span class="line"><span>Select Terminal</span></span>
<span class="line"><span>Change Character Encoding to Western (ASCII)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Here is a forum entry that discusses this in more detail with specifics for Linux: <a href="https://unix.stackexchange.com/questions/78776/characters-encodings-supported-by-more-cat-and-less" target="_blank" rel="noreferrer">character encodings supported by more cat and less</a>.</p>`,8)])])}const h=a(i,[["render",r]]);export{m as __pageData,h as default};
